:root{

  --primary-color:#0d6efd;
  --secondary-color:#ff6b00;

  --success-color:#16a34a;
  --danger-color:#dc2626;
  --warning-color:#f59e0b;

  --white:#ffffff;
  --black:#000000;

  --text-color:#333333;
  --text-light:#666666;

  --bg-color:#f5f5f5;
  --card-bg:#ffffff;

  --border-color:#dddddd;

  --header-height:70px;

  --container-width:1280px;

  --transition:0.3s ease;

  --radius:8px;

  --shadow:0 5px 15px rgba(0,0,0,.08);

}
